namespace ValiCraft.DependencyInjection;

/// <summary>
/// Marks an assembly as containing ValiCraft validators and specifies the module registrar type.
/// This attribute is generated by the ValiCraft source generator and used to discover modules at compile time.
/// </summary>
/// <typeparam name="TModule">The module registrar type that implements <see cref="IValiCraftModule"/>.</typeparam>
[AttributeUsage(AttributeTargets.Assembly, AllowMultiple = false)]
public sealed class ValiCraftModuleAttribute<TModule> : Attribute
    where TModule : IValiCraftModule;
